interface ModalProps {
  title: string;
  children: React.ReactNode;
  modalOpen: boolean;
  setModalOpen: (open: boolean) => void;
}

const Modal = ({ title, children, modalOpen, setModalOpen }: ModalProps) => (
  <ReactModal
    isOpen={modalOpen}
    onRequestClose={() => setModalOpen(false)}
    overlayClassName="features-modal-overlay"
    className="features-modal-content"
    contentLabel="Features modal"
    shouldFocusAfterRender={true}
    shouldCloseOnOverlayClick={true}
    shouldCloseOnEsc={true}
    shouldReturnFocusAfterClose={true}
    closeTimeoutMS={500}
  >
    <div className="container-fluid d-flex flex-column h-100 p-4">
      <h5 className="display-5 mb-4">{title}</h5>
      {children}
    </div>
    <CloseButton setModalOpen={() => setModalOpen(false)} />
  </ReactModal>
);

